# Category: serverless_security

import os
import json
import logging
import urllib.parse
from typing import Any, Dict, List

import boto3
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3_client = boto3.client("s3")
sns_client = boto3.client("sns")

OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET", "")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
OUTPUT_PREFIX = os.environ.get("OUTPUT_PREFIX", "processed/")
NOTIFICATION_ENABLED = os.environ.get("NOTIFICATION_ENABLED", "true").lower() == "true"


def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    logger.info("Received event: %s", json.dumps(event))

    results: List[Dict[str, Any]] = []
    records = event.get("Records", [])

    for record in records:
        try:
            result = process_record(record)
            results.append({"status": "ok", **result})
        except Exception as exc:
            logger.exception("Error processing record: %s", exc)
            results.append({"status": "error", "error": str(exc), "record": record})

    return {
        "statusCode": 200,
        "body": json.dumps({"results": results}),
    }


def process_record(record: Dict[str, Any]) -> Dict[str, Any]:
    s3_info = record.get("s3", {})
    bucket = s3_info.get("bucket", {}).get("name")
    key = s3_info.get("object", {}).get("key")

    if not bucket or not key:
        raise ValueError("Missing bucket or key in S3 event record")

    key = urllib.parse.unquote_plus(key)
    logger.info("Processing s3://%s/%s", bucket, key)

    obj = s3_client.get_object(Bucket=bucket, Key=key)
    content_type = obj.get("ContentType", "application/octet-stream")
    body = obj["Body"].read()

    processed_payload = build_processed_payload(bucket, key, content_type, body)

    output_bucket = OUTPUT_BUCKET or bucket
    output_key = f"{OUTPUT_PREFIX.rstrip('/')}/{key}".replace("//", "/")

    s3_client.put_object(
        Bucket=output_bucket,
        Key=output_key,
        Body=processed_payload.encode("utf-8"),
        ContentType="application/json",
    )

    message = {
        "source_bucket": bucket,
        "source_key": key,
        "output_bucket": output_bucket,
        "output_key": output_key,
        "content_type": content_type,
        "status": "processed",
    }

    if NOTIFICATION_ENABLED and SNS_TOPIC_ARN:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject="Image processed",
            Message=json.dumps(message),
        )

    logger.info("Finished processing s3://%s/%s -> s3://%s/%s", bucket, key, output_bucket, output_key)
    return message


def build_processed_payload(bucket: str, key: str, content_type: str, body: bytes) -> str:
    size_bytes = len(body)
    payload = {
        "source_bucket": bucket,
        "source_key": key,
        "content_type": content_type,
        "size_bytes": size_bytes,
        "note": "MVP placeholder processing. Add image analysis/transforms here.",
    }
    return json.dumps(payload, indent=2)


